queries.sparql:
PREFIX : <http://ambrosia.example.org/jobpostings#>
PREFIX p: <http://ambrosia.example.org/jobpostings/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?casetype ?description WHERE {
  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:testCaseID ?cg . ?child a :Test_Cases ; p:testCaseID ?cg . ?l p:testerID ?pg . ?parent a :Quality_Assurance_Testers ; p:testerID ?pg . } GROUP BY ?child }
  ?child p:caseType ?casetype .
  ?child p:description ?description .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :Quality_Assurance_Testers } }
  FILTER(?nf = ?total)
}

